        """Handle both Event objects and raw topic/payload calls."""
        if isinstance(event, FakeEvent):
            self._published.append(event)
            listeners = self._subscribers.get(event.topic, [])
            for listener in listeners:
                try:
                    listener(event)
                except Exception:
                    pass
        else:
            # Handle case where event is already an Event-like object
            self._published.append(event)
            topic = getattr(event, 'topic', None)
